/**
 * Notification model — core types for the notification system.
 *
 * All notification channels (email, webhook, SMS, in-app) share these
 * common types. Channel-specific data goes in the `metadata` field.
 */

/**
 * Supported notification types. Add new types here as the system grows.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channels for notifications.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in_app';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by a notification adapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  notificationId: string;
  channel: NotificationChannel;
  error?: string;
}

/**
 * A persisted notification record.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  status: 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * NotificationAdapter — interface for all notification delivery channels.
 *
 * CONSTRAINT: All notification adapters MUST implement this interface.
 * The NotificationService dispatches to adapters by channel; each adapter
 * handles the transport-specific delivery (email, webhook, SMS, etc.).
 *
 * Adapters are registered with NotificationService via registerAdapter().
 * Multiple adapters can be registered for different channels.
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /**
   * The channel this adapter handles.
   */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a result indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory.
 * Replace the send() method body with a real email provider
 * (e.g., SendGrid, SES, SMTP) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateEmailId(): string {
  return `email-${String(nextId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextId = 1;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub: stores in-memory. Replace with real provider for production.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const emailId = generateEmailId();

    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: emailId,
      channel: 'email',
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Fully event-driven via EventBus.
 * - All notification triggers come through EventBus subscriptions.
 * - Delivery is delegated to NotificationAdapter implementations.
 * - Adapters are registered by channel (email, webhook, SMS, etc.).
 *
 * CONSTRAINTS:
 * - All notifications MUST originate from EventBus events.
 * - All delivery channels MUST implement NotificationAdapter interface.
 * - Events carry all data needed — handlers do NOT perform additional lookups.
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a given channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the previous one.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers — all notification triggers come through EventBus.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Sending welcome notification for user ${event.user.id}`);

    await this.sendNotification({
      type: 'welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      channel: 'email',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  async sendNotification(payload: NotificationPayload): Promise<void> {
    const id = generateNotificationId();
    const adapter = this.adapters.get(payload.channel);

    let status: 'sent' | 'failed' = 'sent';

    if (adapter) {
      const result = await adapter.send(payload);
      if (!result.success) {
        this.logger.error(`Adapter failed for ${payload.channel}: ${result.error}`);
        status = 'failed';
      }
    } else {
      this.logger.info(`No adapter for channel ${payload.channel}, storing notification in-memory`);
    }

    const notification: Notification = {
      id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      status,
      sentAt: new Date(),
      metadata: payload.metadata,
    };

    this.notifications.push(notification);
    this.logger.info(`Notification ${status}: ${id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

